import { useState, useEffect, useRef, useCallback } from "react";

// ═══════════════════════════════════════════════════════
// STORAGE
// ═══════════════════════════════════════════════════════
const store = {
  async get(key, shared = false) {
    try {
      if (window.storage) {
        const r = await window.storage.get(key, shared);
        return r ? JSON.parse(r.value) : null;
      }
    } catch {}
    try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : null; } catch { return null; }
  },
  async set(key, val, shared = false) {
    try {
      if (window.storage) { await window.storage.set(key, JSON.stringify(val), shared); return; }
    } catch {}
    try { localStorage.setItem(key, JSON.stringify(val)); } catch {}
  },
};

// ═══════════════════════════════════════════════════════
// SESSION ID  (identifica este dispositivo)
// ═══════════════════════════════════════════════════════
const SESSION_ID = (() => {
  let id = sessionStorage.getItem("ox_session_id");
  if (!id) { id = Math.random().toString(36).substr(2, 6).toUpperCase(); sessionStorage.setItem("ox_session_id", id); }
  return id;
})();


