// ═══════════════════════════════════════════════════════
// GAME STATE + REAL-TIME SYNC
// ═══════════════════════════════════════════════════════
const DEF_CONFIG = { format: "5x5", firstGameRule: "sorteio", mensalistaPriority: true, maxPlayers: 50 };
const LIVE_KEY   = "ox_live_v2";
const CFG_KEY    = "ox_config_v2";
const POLL_MS    = 1800;

function useGame() {
  const [players,  setPlayers]  = useState([]);
  const [arrived,  setArrived]  = useState([]);
  const [teamA,    setTeamA]    = useState([]);
  const [teamB,    setTeamB]    = useState([]);
  const [bench,    setBench]    = useState([]);
  const [config,   setConfig]   = useState(DEF_CONFIG);
  const [results,  setResults]  = useState([]);
  const [matchNum, setMatchNum] = useState(0);
  const [started,  setStarted]  = useState(false);
  const [syncStatus, setSyncStatus] = useState("idle"); // "idle"|"ok"|"err"
  const [onlineCount, setOnlineCount] = useState(1);

  const myLastWrite = useRef(0);
  const ready       = useRef(false);
  const writing     = useRef(false);

  // Pack all live state into one object
  const pack = (p, a, tA, tB, b, r, mn, st) => ({
    _ts: Date.now(), _sid: SESSION_ID,
    players: p, arrived: a, teamA: tA, teamB: tB, bench: b,
    results: r, matchNum: mn, started: st,
  });

  // Write to shared storage
  const pushState = useCallback(async (p, a, tA, tB, b, r, mn, st) => {
    if (writing.current) return;
    writing.current = true;
    const data = pack(p, a, tA, tB, b, r, mn, st);
    myLastWrite.current = data._ts;
    try {
      await store.set(LIVE_KEY, data, true);
      setSyncStatus("ok");
    } catch { setSyncStatus("err"); }
    writing.current = false;
  }, []);

  // Apply remote state
  const applyRemote = useCallback((d) => {
    setPlayers(d.players || []);
    setArrived(d.arrived || []);
    setTeamA(d.teamA   || []);
    setTeamB(d.teamB   || []);
    setBench(d.bench   || []);
    setResults(d.results || []);
    setMatchNum(d.matchNum || 0);
    setStarted(d.started   || false);
  }, []);

  // ── Bootstrap ─────────────────────────────────────────
  useEffect(() => {
    (async () => {
      // Load config (personal)
      const cfg = await store.get(CFG_KEY, false);
      if (cfg) setConfig(prev => ({ ...prev, ...cfg }));

      // Load shared live state
      const live = await store.get(LIVE_KEY, true);
      if (live) { applyRemote(live); myLastWrite.current = live._ts || 0; }

      ready.current = true;
      setSyncStatus("ok");

      // Heartbeat: announce this session
      await store.set("ox_hb_" + SESSION_ID, { ts: Date.now() }, true);
    })();
  }, []);

  // ── Poll for remote changes ───────────────────────────
  useEffect(() => {
    const interval = setInterval(async () => {
      if (!ready.current) return;
      try {
        const live = await store.get(LIVE_KEY, true);
        if (live && live._ts > myLastWrite.current) {
          myLastWrite.current = live._ts;
          applyRemote(live);
          setSyncStatus("ok");
        }
        // Heartbeat
        await store.set("ox_hb_" + SESSION_ID, { ts: Date.now() }, true);
        // Count online (list sessions active in last 15s)
        if (window.storage) {
          try {
            const keys = await window.storage.list("ox_hb_", true);
            if (keys?.keys) {
              let cnt = 0;
              const now = Date.now();
              for (const k of keys.keys) {
                try {
                  const hb = await window.storage.get(k, true);
                  if (hb) {
                    const val = JSON.parse(hb.value);
                    if (now - val.ts < 15000) cnt++;
                  }
                } catch {}
              }
              setOnlineCount(Math.max(1, cnt));
            }
          } catch {}
        }
      } catch { setSyncStatus("err"); }
    }, POLL_MS);
    return () => clearInterval(interval);
  }, []);

  // Save config separately (personal)
  useEffect(() => {
    if (!ready.current) return;
    store.set(CFG_KEY, config, false);
  }, [config]);

  // ── Sync helper: wrap any state mutation ──────────────
  const sync = useCallback((newP, newA, newTA, newTB, newB, newR, newMN, newST) => {
    if (!ready.current) return;
    pushState(newP, newA, newTA, newTB, newB, newR, newMN, newST);
  }, [pushState]);

  // ── Player management ─────────────────────────────────
  const addPlayer = (p) => {
    const np = { ...p, id: crypto.randomUUID() };
    setPlayers(prev => { const n = [...prev, np]; sync(n, arrived, teamA, teamB, bench, results, matchNum, started); return n; });
  };
  const removePlayer = (id) => {
    setPlayers(prev => {
      const p = prev.filter(x => x.id !== id);
      setArrived(a => { const na = a.filter(x => x.id !== id); sync(p, na, teamA, teamB, bench, results, matchNum, started); return na; });
      return p;
    });
  };
  const updatePlayer = (id, upd) => {
    setPlayers(prev => { const p = prev.map(x => x.id === id ? { ...x, ...upd } : x); sync(p, arrived, teamA, teamB, bench, results, matchNum, started); return p; });
  };

  // ── Arrival ───────────────────────────────────────────
  const markArrival = (id) => {
    setPlayers(all => {
      const player = all.find(p => p.id === id);
      if (!player) return all;
      setArrived(prev => {
        if (prev.find(p => p.id === id)) return prev;
        const ap = { ...player, arrivalOrder: prev.length + 1 };
        const na = [...prev, ap];
        setBench(b => {
          setStarted(s => {
            const nb = s ? [...b, ap] : b;
            sync(all, na, teamA, teamB, nb, results, matchNum, s);
            return s;
          });
          return started ? [...b, ap] : b;
        });
        return na;
      });
      return all;
    });
  };
  const removeArrival = (id) => {
    setArrived(prev => {
      const na = prev.filter(p => p.id !== id).map((p, i) => ({ ...p, arrivalOrder: i + 1 }));
      const nb = bench.filter(p => p.id !== id);
      const nta = teamA.filter(p => p.id !== id);
      const ntb = teamB.filter(p => p.id !== id);
      setBench(nb); setTeamA(nta); setTeamB(ntb);
      sync(players, na, nta, ntb, nb, results, matchNum, started);
      return na;
    });
  };
  const reorderArrival = (id, dir) => {
    setArrived(prev => {
      const idx = prev.findIndex(p => p.id === id);
      const ti  = dir === "up" ? idx - 1 : idx + 1;
      if (ti < 0 || ti >= prev.length) return prev;
      const arr = [...prev]; [arr[idx], arr[ti]] = [arr[ti], arr[idx]];
      const na = arr.map((p, i) => ({ ...p, arrivalOrder: i + 1 }));
      sync(players, na, teamA, teamB, bench, results, matchNum, started);
      return na;
    });
  };
  const resetArrivals = () => {
    setArrived([]); setTeamA([]); setTeamB([]); setBench([]); setStarted(false); setMatchNum(0); setResults([]);
    sync(players, [], [], [], [], [], 0, false);
  };

  // ── Config ────────────────────────────────────────────
  const updateConfig = (upd) => setConfig(prev => ({ ...prev, ...upd }));

  // ── Teams ─────────────────────────────────────────────
  const perTeam = useCallback(() => parseInt(config.format) || 5, [config]);

  const generateTeams = () => {
    const n = perTeam();
    const shuffle = arr => { const a = [...arr]; for (let i = a.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [a[i], a[j]] = [a[j], a[i]]; } return a; };
    setArrived(arr => {
      const ms = arr.filter(p => p.status === "mensalista");
      const av = arr.filter(p => p.status === "avulso");
      const ordered = config.firstGameRule === "sorteio"
        ? [...shuffle(ms), ...shuffle(av)]
        : [...ms.sort((a, b) => a.arrivalOrder - b.arrivalOrder), ...av.sort((a, b) => a.arrivalOrder - b.arrivalOrder)];
      const nta = [], ntb = [];
      ordered.slice(0, n * 2).forEach((p, i) => (i % 2 === 0 ? nta : ntb).push(p));
      const nb = ordered.slice(n * 2);
      setTeamA(nta); setTeamB(ntb); setBench(nb); setStarted(true); setMatchNum(1);
      sync(players, arr, nta, ntb, nb, results, 1, true);
      return arr;
    });
  };

  // ── Match ─────────────────────────────────────────────
  const recordResult = (winner) => {
    const n = perTeam();
    setTeamA(tA => {
      setTeamB(tB => {
        setBench(bch => {
          const winning = winner === "A" ? [...tA] : [...tB];
          const losing  = winner === "A" ? [...tB] : [...tA];
          const nr  = [...results, { id: crypto.randomUUID(), matchNumber: matchNum, teamA: [...tA], teamB: [...tB], winner }];
          const newBench = [...bch, ...losing];
          const challengers = newBench.slice(0, n);
          const rest = newBench.slice(n);
          const nta = winner === "A" ? winning : challengers;
          const ntb = winner === "B" ? winning : challengers;
          const nmn = matchNum + 1;
          setResults(nr); setTeamA(nta); setTeamB(ntb); setMatchNum(nmn);
          sync(players, arrived, nta, ntb, rest, nr, nmn, started);
          return rest;
        });
        return tB;
      });
      return tA;
    });
  };

  const undoLast = () => {
    setResults(prev => {
      if (!prev.length) return prev;
      const last = prev[prev.length - 1];
      const nr = prev.slice(0, -1);
      const nmn = last.matchNumber;
      setTeamA(last.teamA); setTeamB(last.teamB); setMatchNum(nmn);
      sync(players, arrived, last.teamA, last.teamB, bench, nr, nmn, started);
      return nr;
    });
  };

  // ── DnD moves ─────────────────────────────────────────
  const swapBetweenTeams = (id, fromTeam) => {
    if (fromTeam === "A") {
      setTeamA(t => {
        const p = t.find(x => x.id === id); if (!p) return t;
        const nta = t.filter(x => x.id !== id);
        setTeamB(b => { const ntb = [...b, p]; sync(players, arrived, nta, ntb, bench, results, matchNum, started); return ntb; });
        return nta;
      });
    } else {
      setTeamB(t => {
        const p = t.find(x => x.id === id); if (!p) return t;
        const ntb = t.filter(x => x.id !== id);
        setTeamA(b => { const nta = [...b, p]; sync(players, arrived, nta, ntb, bench, results, matchNum, started); return nta; });
        return ntb;
      });
    }
  };

  const moveToBench = (id, fromTeam) => {
    if (fromTeam === "A") {
      setTeamA(t => {
        const p = t.find(x => x.id === id); if (!p) return t;
        const nta = t.filter(x => x.id !== id);
        setBench(b => { const nb = [...b, p]; sync(players, arrived, nta, teamB, nb, results, matchNum, started); return nb; });
        return nta;
      });
    } else {
      setTeamB(t => {
        const p = t.find(x => x.id === id); if (!p) return t;
        const ntb = t.filter(x => x.id !== id);
        setBench(b => { const nb = [...b, p]; sync(players, arrived, teamA, ntb, nb, results, matchNum, started); return nb; });
        return ntb;
      });
    }
  };

  const moveToTeam = (id, toTeam) => {
    setBench(b => {
      const p = b.find(x => x.id === id); if (!p) return b;
      const nb = b.filter(x => x.id !== id);
      if (toTeam === "A") setTeamA(t => { const nta = [...t, p]; sync(players, arrived, nta, teamB, nb, results, matchNum, started); return nta; });
      else setTeamB(t => { const ntb = [...t, p]; sync(players, arrived, teamA, ntb, nb, results, matchNum, started); return ntb; });
      return nb;
    });
  };

  const removeFromMatch = (id) => {
    setTeamA(t => {
      const nta = t.filter(x => x.id !== id);
      setTeamB(b => {
        const ntb = b.filter(x => x.id !== id);
        setBench(bch => {
          const nb = bch.filter(x => x.id !== id);
          setArrived(a => { const na = a.filter(x => x.id !== id).map((p, i) => ({ ...p, arrivalOrder: i + 1 })); sync(players, na, nta, ntb, nb, results, matchNum, started); return na; });
          return nb;
        });
        return ntb;
      });
      return nta;
    });
  };

  const removeAndSub = (outId, inId) => {
    setBench(bch => {
      const sub = bch.find(p => p.id === inId); if (!sub) return bch;
      const nb = bch.filter(p => p.id !== inId);
      setTeamA(t => {
        if (!t.find(p => p.id === outId)) return t;
        const nta = t.map(p => p.id === outId ? sub : p);
        setArrived(a => { const na = a.filter(p => p.id !== outId).map((p, i) => ({ ...p, arrivalOrder: i + 1 })); sync(players, na, nta, teamB, nb, results, matchNum, started); return na; });
        return nta;
      });
      setTeamB(t => {
        if (!t.find(p => p.id === outId)) return t;
        const ntb = t.map(p => p.id === outId ? sub : p);
        setArrived(a => { const na = a.filter(p => p.id !== outId).map((p, i) => ({ ...p, arrivalOrder: i + 1 })); sync(players, na, teamA, ntb, nb, results, matchNum, started); return na; });
        return ntb;
      });
      return nb;
    });
  };

  const addLateNew = (nickname) => {
    const np = { id: crypto.randomUUID(), name: nickname, nickname, status: "avulso" };
    const allP = [...players, np];
    setPlayers(allP);
    setArrived(prev => {
      const ap = { ...np, arrivalOrder: prev.length + 1 };
      const na = [...prev, ap];
      setBench(b => {
        const nb = started ? [...b, ap] : b;
        sync(allP, na, teamA, teamB, nb, results, matchNum, started);
        return nb;
      });
      return na;
    });
  };

  const addLate = (id) => markArrival(id);

  const resetGame = () => {
    setArrived([]); setTeamA([]); setTeamB([]); setBench([]); setStarted(false); setMatchNum(0); setResults([]);
    sync(players, [], [], [], [], [], 0, false);
  };

  const resetAll = async () => {
    await store.set(LIVE_KEY, null, true);
    await store.set(CFG_KEY, DEF_CONFIG, false);
    setPlayers([]); setArrived([]); setTeamA([]); setTeamB([]); setBench([]);
    setConfig(DEF_CONFIG); setResults([]); setMatchNum(0); setStarted(false);
    myLastWrite.current = Date.now();
  };

  return {
    players, arrived, teamA, teamB, bench, config, results, matchNum, started,
    syncStatus, onlineCount,
    addPlayer, removePlayer, updatePlayer,
    markArrival, removeArrival, reorderArrival, resetArrivals,
    updateConfig, generateTeams, perTeam,
    recordResult, undoLast,
    swapBetweenTeams, moveToBench, moveToTeam, removeFromMatch, removeAndSub,
    addLateNew, addLate, resetGame, resetAll,
  };
}

// ═══════════════════════════════════════════════════════
// TOAST
// ═══════════════════════════════════════════════════════
function useToast() {
  const [t, setT]   = useState(null);
  const ref         = useRef(null);
  const show = useCallback((msg) => {
    setT(msg); clearTimeout(ref.current);
    ref.current = setTimeout(() => setT(null), 2500);
  }, []);
  return { t, show };
}

