// ═══════════════════════════════════════════════════════
// KIOSK MODE  (bloqueio de tela)
// ═══════════════════════════════════════════════════════
function KioskPINScreen({ onUnlock, pin }) {
  const [entered, setEntered] = useState("");
  const [shake,   setShake]   = useState(false);

  const handleDigit = (d) => {
    if (d === "⌫") { setEntered(e => e.slice(0, -1)); return; }
    if (entered.length >= 4) return;
    const next = entered + d;
    setEntered(next);
    if (next.length === 4) {
      if (next === pin) { onUnlock(); }
      else {
        setShake(true);
        setTimeout(() => { setEntered(""); setShake(false); }, 700);
      }
    }
  };

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 9999, background: "#09090b", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24 }}>
      <img src={LOGO} alt="Pelada Oxentchê" style={{ width: 120, height: 120, objectFit: "contain", marginBottom: 12, filter: "drop-shadow(0 0 24px rgba(16,185,129,0.4))" }} />
      <div style={{ color: "#52525b", fontSize: 13, marginBottom: 40 }}>🔒 Modo Quiosque — Digite o PIN para sair</div>

      {/* PIN dots */}
      <div style={{ display: "flex", gap: 16, marginBottom: 36, transform: shake ? "translateX(8px)" : "none", transition: "transform .1s" }}>
        {[0,1,2,3].map(i => (
          <div key={i} style={{ width: 18, height: 18, borderRadius: "50%", background: i < entered.length ? (shake ? "#ef4444" : "#10b981") : "#27272a", transition: "background .2s" }} />
        ))}
      </div>

      {/* Numpad */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 14 }}>
        {[1,2,3,4,5,6,7,8,9,"",0,"⌫"].map((d, i) => (
          <button key={i} onClick={() => d !== "" && handleDigit(String(d))}
            disabled={d === ""}
            style={{ width: 80, height: 80, borderRadius: "50%", background: d === "" ? "transparent" : "#18181b", border: "1px solid " + (d === "" ? "transparent" : "#27272a"), color: d === "⌫" ? "#71717a" : "#fff", fontSize: d === "⌫" ? 20 : 26, fontWeight: 700, cursor: d === "" ? "default" : "pointer", transition: "background .1s" }}>
            {d}
          </button>
        ))}
      </div>

      <div style={{ marginTop: 32, color: "#3f3f46", fontSize: 11, textAlign: "center" }}>
        Para sair completamente: use Acesso Guiado (iOS) ou Fixação de Tela (Android)
      </div>
    </div>
  );
}

function KioskInstructions({ onClose }) {
  return (
    <Modal title="📱 Modo Quiosque" onClose={onClose}>
      <p style={{ fontSize: 13, color: "#a1a1aa", lineHeight: 1.7, marginBottom: 16 }}>
        O <strong style={{ color: "#fff" }}>Modo Quiosque</strong> bloqueia o app com PIN, mas para impedir que o usuário saia completamente do app, use os recursos nativos do celular:
      </p>
      <div style={{ background: "#0a2e1a", border: "1px solid #16a34a44", borderRadius: 12, padding: 14, marginBottom: 12 }}>
        <div style={{ fontWeight: 800, color: "#10b981", fontSize: 13, marginBottom: 8 }}>🤖 Android — Fixação de Tela</div>
        <div style={{ fontSize: 12, color: "#a1a1aa", lineHeight: 1.6 }}>
          1. Ative em <em>Configurações → Segurança → Fixação de tela</em><br/>
          2. Abra o app e toque em "Recentes" (quadrado)<br/>
          3. Toque no ícone do app → "Fixar"
        </div>
      </div>
      <div style={{ background: "#0c1a3a", border: "1px solid #1d4ed844", borderRadius: 12, padding: 14, marginBottom: 12 }}>
        <div style={{ fontWeight: 800, color: "#60a5fa", fontSize: 13, marginBottom: 8 }}>🍎 iPhone — Acesso Guiado</div>
        <div style={{ fontSize: 12, color: "#a1a1aa", lineHeight: 1.6 }}>
          1. Ative em <em>Ajustes → Acessibilidade → Acesso Guiado</em><br/>
          2. Abra o app e clique 3× no botão lateral<br/>
          3. Toque em "Iniciar" e defina um código
        </div>
      </div>
      <button onClick={onClose} style={{ width: "100%", padding: "12px 0", borderRadius: 12, background: "#10b981", color: "#fff", fontWeight: 800, fontSize: 15, border: "none", cursor: "pointer" }}>
        Entendido
      </button>
    </Modal>
  );
}

