// ═══════════════════════════════════════════════════════
// PLAYERS PAGE
// ═══════════════════════════════════════════════════════
function PlayersPage({ go, game, toast }) {
  const { players, config, addPlayer, removePlayer, updatePlayer } = game;
  const [form, setForm] = useState(false);
  const [editId, setEid] = useState(null);
  const [name, setName] = useState("");
  const [nick, setNick] = useState("");
  const [status, setSt] = useState("mensalista");
  const ref = useRef();
  const ms = players.filter(p => p.status === "mensalista");
  const av = players.filter(p => p.status === "avulso");

  const openForm = (p = null) => { setEid(p?.id || null); setName(p?.name || ""); setNick(p?.nickname || ""); setSt(p?.status || "mensalista"); setForm(true); setTimeout(() => ref.current?.focus(), 80); };
  const save = () => {
    if (!name.trim()) return;
    const d = { name: name.trim(), nickname: nick.trim() || name.trim(), status };
    if (editId) updatePlayer(editId, d); else addPlayer(d);
    toast.show(editId ? "✅ Atualizado!" : "✅ Adicionado!"); setForm(false); setName(""); setNick(""); setEid(null);
  };

  const Row = ({ p }) => (
    <div style={{ ...S.card, display: "flex", alignItems: "center", gap: 10 }}>
      <Av name={p.nickname} gold={p.status === "mensalista"} />
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontWeight: 700, fontSize: 14, color: "#fff", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.nickname}</div>
        {p.name !== p.nickname && <div style={{ fontSize: 11, color: "#71717a" }}>{p.name}</div>}
      </div>
      <button onClick={() => openForm(p)} style={{ color: "#52525b", background: "none", border: "none", cursor: "pointer", padding: 4 }}><IC.Edit /></button>
      <button onClick={() => updatePlayer(p.id, { status: p.status === "mensalista" ? "avulso" : "mensalista" })}
        style={{ fontSize: 12, background: p.status === "mensalista" ? "#431407" : "#18181b", color: p.status === "mensalista" ? "#f59e0b" : "#71717a", border: "1px solid", borderRadius: 8, padding: "3px 8px", cursor: "pointer" }}>
        {p.status === "mensalista" ? "★" : "☆"}
      </button>
      <button onClick={() => { removePlayer(p.id); toast.show("🗑️ Removido!"); }} style={{ color: "#ef4444", background: "none", border: "none", cursor: "pointer", padding: 4 }}><IC.Trash /></button>
    </div>
  );

  return (
    <div style={{ minHeight: "100vh", background: "#09090b", padding: "16px 16px 32px" }}>
      <div style={{ ...S.row, marginBottom: 20 }}>
        <button onClick={() => go("home")} style={{ color: "#71717a", background: "none", border: "none", cursor: "pointer" }}><IC.Back /></button>
        <span style={{ fontWeight: 900, fontSize: 22, color: "#fff" }}>Jogadores</span>
        <span style={{ marginLeft: "auto", color: "#52525b", fontSize: 13 }}>{players.length}/{config.maxPlayers}</span>
      </div>
      {!form ? (
        <button onClick={() => openForm()} disabled={players.length >= config.maxPlayers} style={{ ...S.btn(), marginBottom: 20, opacity: players.length >= config.maxPlayers ? 0.4 : 1 }}><IC.Plus /><span>Adicionar Jogador</span></button>
      ) : (
        <div style={{ ...S.card, marginBottom: 20 }}>
          <div style={{ fontWeight: 800, fontSize: 14, color: "#fff", marginBottom: 12 }}>{editId ? "Editar" : "Novo"} Jogador</div>
          <input ref={ref} placeholder="Nome" value={name} onChange={e => setName(e.target.value)} onKeyDown={e => e.key === "Enter" && save()} style={{ ...S.inp, marginBottom: 8 }} />
          <input placeholder="Apelido (opcional)" value={nick} onChange={e => setNick(e.target.value)} onKeyDown={e => e.key === "Enter" && save()} style={{ ...S.inp, marginBottom: 10 }} />
          <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
            {[["mensalista", "👑 Mensalista", "#d97706"], ["avulso", "👤 Avulso", "#10b981"]].map(([v, l, c]) => (
              <button key={v} onClick={() => setSt(v)} style={{ flex: 1, padding: "10px 0", borderRadius: 10, fontWeight: 800, fontSize: 13, cursor: "pointer", background: status === v ? c : "#27272a", color: status === v ? "#fff" : "#71717a", border: "none" }}>{l}</button>
            ))}
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setForm(false)} style={{ ...S.outBtn, flex: 1 }}>Cancelar</button>
            <button onClick={save} style={{ ...S.btn(), flex: 1 }}>{editId ? "Atualizar" : "Salvar"}</button>
          </div>
        </div>
      )}
      {ms.length > 0 && <div style={{ marginBottom: 16 }}><div style={S.label}>👑 Mensalistas ({ms.length})</div>{ms.map(p => <Row key={p.id} p={p} />)}</div>}
      {av.length > 0 && <div><div style={S.label}>👤 Avulsos ({av.length})</div>{av.map(p => <Row key={p.id} p={p} />)}</div>}
      {players.length === 0 && <div style={{ textAlign: "center", padding: "60px 0", color: "#52525b" }}><div style={{ fontSize: 48, marginBottom: 12 }}>👥</div><div>Nenhum jogador cadastrado</div></div>}
    </div>
  );
}

