// ═══════════════════════════════════════════════════════
// TOAST UI
// ═══════════════════════════════════════════════════════
function ToastUI({ t }) {
  if (!t) return null;
  return (
    <div style={{ position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)", zIndex: 998, background: "#18181b", border: "1px solid #3f3f46", borderRadius: 12, padding: "10px 18px", fontSize: 14, fontWeight: 700, color: "#fff", boxShadow: "0 8px 32px rgba(0,0,0,0.5)", whiteSpace: "nowrap", maxWidth: "90vw" }}>
      {t}
    </div>
  );
}

// ═══════════════════════════════════════════════════════
// APP ROOT
// ═══════════════════════════════════════════════════════
export default function App() {
  const [page,       setPage]       = useState("home");
  
  // Inject favicon + PWA meta dynamically
  useEffect(() => {
    // Favicon
    const existing = document.querySelector("link[rel*='icon']");
    const link = existing || document.createElement("link");
    link.type = "image/jpeg";
    link.rel  = "shortcut icon";
    link.href = LOGO;
    if (!existing) document.head.appendChild(link);

    // Apple touch icon
    const appleIcon = document.querySelector("link[rel='apple-touch-icon']") || document.createElement("link");
    appleIcon.rel  = "apple-touch-icon";
    appleIcon.href = LOGO;
    if (!document.querySelector("link[rel='apple-touch-icon']")) document.head.appendChild(appleIcon);

    // Theme color
    let meta = document.querySelector("meta[name='theme-color']") || document.createElement("meta");
    meta.name    = "theme-color";
    meta.content = "#09090b";
    if (!document.querySelector("meta[name='theme-color']")) document.head.appendChild(meta);

    // Title
    document.title = "Pelada Oxentchê";

    // Keep screen awake via Wake Lock API
    let wakeLock = null;
    const requestWakeLock = async () => {
      try {
        if ("wakeLock" in navigator) {
          wakeLock = await navigator.wakeLock.request("screen");
        }
      } catch {}
    };
    requestWakeLock();
    const onVisChange = () => { if (document.visibilityState === "visible") requestWakeLock(); };
    document.addEventListener("visibilitychange", onVisChange);

    return () => {
      document.removeEventListener("visibilitychange", onVisChange);
      if (wakeLock) wakeLock.release().catch(() => {});
    };
  }, []);
  const [kioskMode,  setKioskMode]  = useState(false);
  const [kioskPIN,   setKioskPIN]   = useState("0000");
  const [showInstruct, setShowInstruct] = useState(false);
  const game  = useGame();
  const toast = useToast();

  const activateKiosk = () => {
    setKioskMode(true);
    // Try fullscreen
    try {
      const el = document.documentElement;
      if (el.requestFullscreen) el.requestFullscreen();
      else if (el.webkitRequestFullscreen) el.webkitRequestFullscreen();
    } catch {}
  };

  // Intercept Escape / back to keep kiosk
  useEffect(() => {
    const onKey = (e) => { if (kioskMode && (e.key === "Escape" || e.key === "Back")) e.preventDefault(); };
    document.addEventListener("keydown", onKey, true);
    return () => document.removeEventListener("keydown", onKey, true);
  }, [kioskMode]);

  // Fullscreen change listener
  useEffect(() => {
    const onFS = () => { if (!document.fullscreenElement && !document.webkitFullscreenElement) { /* exited fullscreen — kiosk PIN still active */ } };
    document.addEventListener("fullscreenchange", onFS);
    document.addEventListener("webkitfullscreenchange", onFS);
    return () => { document.removeEventListener("fullscreenchange", onFS); document.removeEventListener("webkitfullscreenchange", onFS); };
  }, []);

  return (
    <div style={{ fontFamily: "'Inter',system-ui,sans-serif", maxWidth: 480, margin: "0 auto", minHeight: "100vh", background: "#09090b" }}>
      <ToastUI t={toast.t} />

      {/* Kiosk PIN screen overlay */}
      {kioskMode && (
        <KioskPINScreen pin={kioskPIN} onUnlock={() => {
          setKioskMode(false);
          try { if (document.exitFullscreen) document.exitFullscreen(); else if (document.webkitExitFullscreen) document.webkitExitFullscreen(); } catch {}
        }} />
      )}

      {/* Instructions modal */}
      {showInstruct && <KioskInstructions onClose={() => setShowInstruct(false)} />}

      {/* Main pages */}
      {page === "home"     && <HomePage go={setPage} game={game} onKiosk={activateKiosk} onShowInstructions={() => setShowInstruct(true)} />}
      {page === "players"  && <PlayersPage  go={setPage} game={game} toast={toast} />}
      {page === "arrival"  && <ArrivalPage  go={setPage} game={game} toast={toast} />}
      {page === "teams"    && <TeamsPage    go={setPage} game={game} toast={toast} />}
      {page === "match"    && <MatchPage    go={setPage} game={game} toast={toast} />}
      {page === "history"  && <HistoryPage  go={setPage} game={game} />}
      {page === "settings" && <SettingsPage go={setPage} game={game} toast={toast} kioskPIN={kioskPIN} setKioskPIN={setKioskPIN} />}
      {page === "about"    && <AboutPage    go={setPage} />}
    </div>
  );
}
